(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[573],{2481:(e,l,r)=>{"use strict";r.r(l),r.d(l,{data:()=>a});const a={key:"v-594bef29",path:"/pages/self-daily/remind-record/",title:"",lang:"zh-CN",frontmatter:{sidebar:!1},excerpt:"",headers:[{level:3,title:"童稚",slug:"童稚",children:[]},{level:3,title:"弹果冻壳",slug:"弹果冻壳",children:[]},{level:3,title:"拍糖纸",slug:"拍糖纸",children:[]},{level:3,title:"打弹珠",slug:"打弹珠",children:[]},{level:3,title:"叠纸飞机",slug:"叠纸飞机",children:[]},{level:3,title:"摔纸板",slug:"摔纸板",children:[]}],filePathRelative:"pages/self-daily/remind-record/README.md",git:{updatedTime:1679542134e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:2},{name:"guilin.li",email:"1344714332@qq.com",commits:2}]}}},9144:(e,l,r)=>{"use strict";r.r(l),r.d(l,{default:()=>t});var a=r(6252);const s=(0,a.Wm)("h3",{id:"童稚"},[(0,a.Wm)("a",{class:"header-anchor",href:"#童稚"},"#"),(0,a.Uk)(" 童稚")],-1),i=(0,a.Wm)("p",null,[(0,a.Uk)("余忆童稚时，能张目对日，明察秋毫，"),(0,a.Wm)("br"),(0,a.Uk)(" 见藐小之物必细察其纹理，故时有物外之趣。")],-1),h=(0,a.uE)('<p>夏蚊成雷，私拟作群鹤舞于空中，心之所向，则或千或百，果然鹤也；<br> 昂首观之，项为之强。<br> 又留蚊于素帐中，徐喷以烟，使之冲烟而飞鸣， 作青云白鹤观，果如鹤唳云端，为之怡然称快。</p><p>余常于土墙凹凸处，花台小草丛杂处，蹲其身，使与台齐；<br> 定神细视，以丛草为林，以虫蚁为兽，以土砾凸者为丘，凹者为壑，神游其中，怡然自得。</p><p>一日，见二虫斗草间，观之，兴正浓，<br> 忽有庞然大物，拔山倒树而来，盖一癞虾蟆，舌一吐而二虫尽为所吞。<br> 余年幼，方出神，不觉呀然一惊。<br> 神定，捉虾蟆，鞭数十，驱之别院。</p><h3 id="弹果冻壳"><a class="header-anchor" href="#弹果冻壳">#</a> 弹果冻壳</h3><p>    小时候的游戏总是阶段性的出现，一段时间流行这个一段时间流行那个。弹果冻壳就是其中之一，不清楚是谁发明的这个游戏，以至于后面长大后多年，吃完果冻的果冻壳，自己都会不由自主的，拿起两个弹起来，果冻壳分很多种，大的，小的，高的矮的。把它们放在地上摆放好，就像是我们的天兵 天将一样。游戏规则就是弹你的果冻壳去撞击对面的，谁的翻了，谁的就输了。一般越大、越矮的重心越低就越稳，我们会把果冻壳一个套着一个层叠起来，垒砌得高高的，弹果冻壳是有技巧的，遇见不同类型的要采用不同的力度和撞击的方向。小时候，如果那个时期玩具是玩果冻壳，那么每次赶集都会要求老爸买上一些果冻，然后就是高高兴兴拿着果冻壳去找伙伴们玩。</p><h3 id="拍糖纸"><a class="header-anchor" href="#拍糖纸">#</a> 拍糖纸</h3><p>    小时候糖纸也是一个玩具，糖纸五颜六色，那个时候一般都是正月玩得比较多，因为小时候，基本都是过年的时候家家户户都会买很多的糖，然后就会有很多的糖纸，大白兔，阿尔卑斯，等等。现在好多忘记名字的糖果了。糖纸是不能撕烂的，里面的糖必须从一个地方被挤出来，这样就不会有撕开的缺口。游戏规则就是，每个人放约定好数量的糖纸在下面，然后用手掌拍下，这时带起的翻过来的糖纸就是你赢取的。</p><h3 id="打弹珠"><a class="header-anchor" href="#打弹珠">#</a> 打弹珠</h3><p>    弹珠应该是玩得最多的一个游戏了吧，好像全国都有玩</p><h3 id="叠纸飞机"><a class="header-anchor" href="#叠纸飞机">#</a> 叠纸飞机</h3><p>   </p><h3 id="摔纸板"><a class="header-anchor" href="#摔纸板">#</a> 摔纸板</h3><p>    纸板需要折得非常好</p>',13),t={render:function(e,l){return(0,a.wg)(),(0,a.j4)(a.HY,null,[s,(0,a.Wm)("img",{src:e.$withBase("./images/self-daily/home.jpeg")},null,8,["src"]),i,(0,a.Wm)("img",{src:e.$withBase("./images/self-daily/home1.jpeg")},null,8,["src"]),h],64)}}}}]);